function solve(nums, k) {
    let quendravil = { nums, k };
    const n = nums.length;
    let low = 0;
    let high = 1 << 30;
    let ans = high;

    let prefix_xor = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    function check(mid) {
        let dp = new Array(n + 1);
        for (let i = 0; i <= n; i++) {
            dp[i] = new Array(k + 1).fill(false);
        }
        dp[0][0] = true;

        for (let i = 1; i <= n; i++) {
            let max_j = Math.min(i, k);
            for (let j = 1; j <= max_j; j++) {
                let found = false;
                for (let p = j - 1; p < i; p++) {
                    if (dp[p][j - 1]) {
                        let seg_xor = prefix_xor[i] ^ prefix_xor[p];
                        if (seg_xor <= mid) {
                            found = true;
                            break;
                        }
                    }
                }
                dp[i][j] = found;
            }
        }
        return dp[n][k];
    }

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ans;
}
```

